-- ============================================================n-- FIX: Crear tablas faltantes de 003_finances.sql en orden correcton-- Ejecutar TODO de una sola vez en Supabase SQL Editorn-- ============================================================nn-- 1. EXPENSES (primero, sin dependencias de otras tablas nuevas)nCREATE TABLE IF NOT EXISTS expenses(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,n  product_id UUID REFERENCES products(id) ON DELETE SET NULL,n  category TEXT NOT NULL CHECK(category IN('ppc','software','va_services','samples','photography','shipping_forwarder','customs','prep_center','storage_3pl','travel','other')),n  subcategory TEXT,n  description TEXT NOT NULL,n  amount DECIMAL(10,2) NOT NULL CHECK(amount >= 0),n  currency TEXT DEFAULT 'USD',n  exchange_rate DECIMAL(10,4) DEFAULT 1,n  amount_usd DECIMAL(10,2) GENERATED ALWAYS AS(amount / NULLIF(exchange_rate,0)) STORED,n  expense_date DATE NOT NULL DEFAULT CURRENT_DATE,n  recurring BOOLEAN DEFAULT false,n  recurring_frequency TEXT CHECK(recurring_frequency IN('weekly','monthly','quarterly','yearly')),n  vendor TEXT,n  receipt_url TEXT,n  notes TEXT,n  created_at TIMESTAMPTZ DEFAULT now(),n  updated_at TIMESTAMPTZ DEFAULT now()n);nn-- 2. AMAZON_PAYOUTSnCREATE TABLE IF NOT EXISTS amazon_payouts(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,n  payout_period_start DATE NOT NULL,n  payout_period_end DATE NOT NULL,n  amount DECIMAL(10,2) NOT NULL,n  currency TEXT DEFAULT 'USD',n  status TEXT CHECK(status IN('pending','transferred','failed')) DEFAULT 'pending',n  amazon_reference TEXT,n  bank_account_last4 TEXT,n  transfer_date DATE,n  marketplace TEXT DEFAULT 'US',n  notes TEXT,n  created_at TIMESTAMPTZ DEFAULT now()n);nn-- 3. FBA_SHIPMENTS (depende de purchase_orders que ya deberia existir)nCREATE TABLE IF NOT EXISTS fba_shipments(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,n  po_id UUID REFERENCES purchase_orders(id) ON DELETE SET NULL,n  shipment_name TEXT NOT NULL,n  shipment_id TEXT,n  amazon_reference_id TEXT,n  destination_fulfillment_center TEXT,n  destination_address TEXT,n  status TEXT CHECK(status IN('working','ready_to_ship','shipped','in_transit','delivered','checked_in','receiving','closed','cancelled')) DEFAULT 'working',n  shipping_method TEXT CHECK(shipping_method IN('small_parcel','ltl','ftl','air','sea')),n  carrier TEXT,n  tracking_number TEXT,n  box_count INTEGER DEFAULT 0,n  total_units INTEGER DEFAULT 0,n  total_weight_kg DECIMAL(10,3),n  shipping_cost DECIMAL(10,2) DEFAULT 0,n  ship_date DATE,n  estimated_arrival DATE,n  actual_arrival DATE,n  notes TEXT,n  created_at TIMESTAMPTZ DEFAULT now(),n  updated_at TIMESTAMPTZ DEFAULT now()n);nn-- 4. FBA_SHIPMENT_ITEMS (depende de fba_shipments y products)nCREATE TABLE IF NOT EXISTS fba_shipment_items(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  shipment_id UUID NOT NULL REFERENCES fba_shipments(id) ON DELETE CASCADE,n  product_id UUID NOT NULL REFERENCES products(id) ON DELETE CASCADE,n  quantity INTEGER NOT NULL CHECK(quantity > 0),n  quantity_received INTEGER DEFAULT 0,n  msKU TEXT,n  fnSKU TEXT,n  created_at TIMESTAMPTZ DEFAULT now()n);nn-- 5. RETURNS (depende de products)nCREATE TABLE IF NOT EXISTS returns(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,n  product_id UUID NOT NULL REFERENCES products(id) ON DELETE CASCADE,n  order_id TEXT,n  amazon_return_id TEXT,n  quantity INTEGER NOT NULL CHECK(quantity > 0),n  return_reason TEXT CHECK(return_reason IN('defective','damaged_by_carrier','customer_damaged','different_from_description','expired_item','fraud','missing_parts','no_longer_wanted','not_as_described','ordered_wrong_item','quality_not_acceptable','arrived_late','undeliverable','unauthorized_purchase','other')),n  customer_comment TEXT,n  refund_amount DECIMAL(10,2),n  status TEXT CHECK(status IN('requested','received_at_customer','in_transit','received_at_fc','inspected','refunded','reimbursed','disposed')) DEFAULT 'requested',n  disposition TEXT CHECK(disposition IN('sellable','unsellable','pending')),n  return_date DATE,n  received_date DATE,n  inspected_date DATE,n  notes TEXT,n  created_at TIMESTAMPTZ DEFAULT now(),n  updated_at TIMESTAMPTZ DEFAULT now()n);nn-- 6. REIMBURSEMENTS (depende de products y returns)nCREATE TABLE IF NOT EXISTS reimbursements(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,n  product_id UUID REFERENCES products(id) ON DELETE SET NULL,n  return_id UUID REFERENCES returns(id) ON DELETE SET NULL,n  amazon_case_id TEXT,n  reimbursement_type TEXT CHECK(reimbursement_type IN('lost_inbound','damaged_inbound','lost_warehouse','damaged_warehouse','customer_return','removal_order','other')),n  quantity INTEGER NOT NULL CHECK(quantity > 0),n  amount DECIMAL(10,2) NOT NULL,n  currency TEXT DEFAULT 'USD',n  status TEXT CHECK(status IN('pending','submitted','approved','rejected','paid')) DEFAULT 'pending',n  issue_date DATE,n  submitted_date DATE,n  approved_date DATE,n  paid_date DATE,n  notes TEXT,n  created_at TIMESTAMPTZ DEFAULT now(),n  updated_at TIMESTAMPTZ DEFAULT now()n);nn-- 7. PPC_CAMPAIGNS (depende de products)nCREATE TABLE IF NOT EXISTS ppc_campaigns(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,n  product_id UUID REFERENCES products(id) ON DELETE SET NULL,n  campaign_name TEXT NOT NULL,n  campaign_id TEXT,n  campaign_type TEXT CHECK(campaign_type IN('sp_auto','sp_manual_keyword','sp_manual_product','sb','sd')),n  marketplace TEXT DEFAULT 'US',n  status TEXT CHECK(status IN('enabled','paused','archived')) DEFAULT 'enabled',n  daily_budget DECIMAL(10,2) DEFAULT 0,n  created_at TIMESTAMPTZ DEFAULT now(),n  updated_at TIMESTAMPTZ DEFAULT now()n);nn-- 8. PPC_DAILY_METRICS (depende de ppc_campaigns)nCREATE TABLE IF NOT EXISTS ppc_daily_metrics(n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  campaign_id UUID NOT NULL REFERENCES ppc_campaigns(id) ON DELETE CASCADE,n  metric_date DATE NOT NULL,n  impressions INTEGER DEFAULT 0,n  clicks INTEGER DEFAULT 0,n  spend DECIMAL(10,2) DEFAULT 0,n  sales DECIMAL(10,2) DEFAULT 0,n  orders INTEGER DEFAULT 0,n  units INTEGER DEFAULT 0,n  acos DECIMAL(5,2) GENERATED ALWAYS AS(CASE WHEN sales > 0 THEN ROUND((spend / sales) * 100, 2) ELSE 0 END) STORED,n  roas DECIMAL(5,2) GENERATED ALWAYS AS(CASE WHEN spend > 0 THEN ROUND(sales / spend, 2) ELSE 0 END) STORED,n  ctr DECIMAL(5,4) GENERATED ALWAYS AS(CASE WHEN impressions > 0 THEN ROUND(clicks::DECIMAL / impressions, 4) ELSE 0 END) STORED,n  cpc DECIMAL(10,4) GENERATED ALWAYS AS(CASE WHEN clicks > 0 THEN ROUND(spend / clicks, 4) ELSE 0 END) STORED,n  created_at TIMESTAMPTZ DEFAULT now(),n  UNIQUE(campaign_id, metric_date)n);nn-- 9. INDEXESnCREATE INDEX IF NOT EXISTS idx_expenses_user ON expenses(user_id);nCREATE INDEX IF NOT EXISTS idx_expenses_date ON expenses(expense_date DESC);nCREATE INDEX IF NOT EXISTS idx_expenses_category ON expenses(category);nCREATE INDEX IF NOT EXISTS idx_expenses_product ON expenses(product_id);nCREATE INDEX IF NOT EXISTS idx_payouts_user ON amazon_payouts(user_id);nCREATE INDEX IF NOT EXISTS idx_payouts_period ON amazon_payouts(payout_period_start DESC);nCREATE INDEX IF NOT EXISTS idx_shipments_user ON fba_shipments(user_id);nCREATE INDEX IF NOT EXISTS idx_shipments_status ON fba_shipments(status);nCREATE INDEX IF NOT EXISTS idx_shipment_items_shipment ON fba_shipment_items(shipment_id);nCREATE INDEX IF NOT EXISTS idx_returns_user ON returns(user_id);nCREATE INDEX IF NOT EXISTS idx_returns_product ON returns(product_id);nCREATE INDEX IF NOT EXISTS idx_returns_status ON returns(status);nCREATE INDEX IF NOT EXISTS idx_reimbursements_user ON reimbursements(user_id);nCREATE INDEX IF NOT EXISTS idx_reimbursements_status ON reimbursements(status);nCREATE INDEX IF NOT EXISTS idx_ppc_campaigns_user ON ppc_campaigns(user_id);nCREATE INDEX IF NOT EXISTS idx_ppc_campaigns_product ON ppc_campaigns(product_id);nCREATE INDEX IF NOT EXISTS idx_ppc_metrics_campaign ON ppc_daily_metrics(campaign_id);nCREATE INDEX IF NOT EXISTS idx_ppc_metrics_date ON ppc_daily_metrics(metric_date DESC);nn-- 10. RLS ENABLEnALTER TABLE expenses ENABLE ROW LEVEL SECURITY;nALTER TABLE amazon_payouts ENABLE ROW LEVEL SECURITY;nALTER TABLE fba_shipments ENABLE ROW LEVEL SECURITY;nALTER TABLE fba_shipment_items ENABLE ROW LEVEL SECURITY;nALTER TABLE returns ENABLE ROW LEVEL SECURITY;nALTER TABLE reimbursements ENABLE ROW LEVEL SECURITY;nALTER TABLE ppc_campaigns ENABLE ROW LEVEL SECURITY;nALTER TABLE ppc_daily_metrics ENABLE ROW LEVEL SECURITY;nn-- 11. RLS POLICIESnCREATE POLICY IF NOT EXISTS "own_expenses" ON expenses FOR ALL USING(auth.uid() = user_id);nCREATE POLICY IF NOT EXISTS "own_payouts" ON amazon_payouts FOR ALL USING(auth.uid() = user_id);nCREATE POLICY IF NOT EXISTS "own_shipments" ON fba_shipments FOR ALL USING(auth.uid() = user_id);nCREATE POLICY IF NOT EXISTS "own_shipment_items" ON fba_shipment_items FOR ALL USING(shipment_id IN(SELECT id FROM fba_shipments WHERE user_id = auth.uid()));nCREATE POLICY IF NOT EXISTS "own_returns" ON returns FOR ALL USING(auth.uid() = user_id);nCREATE POLICY IF NOT EXISTS "own_reimbursements" ON reimbursements FOR ALL USING(auth.uid() = user_id);nCREATE POLICY IF NOT EXISTS "own_ppc_campaigns" ON ppc_campaigns FOR ALL USING(auth.uid() = user_id);nCREATE POLICY IF NOT EXISTS "own_ppc_metrics" ON ppc_daily_metrics FOR ALL USING(campaign_id IN(SELECT id FROM ppc_campaigns WHERE user_id = auth.uid()));nn-- 12. TRIGGERSnCREATE TRIGGER IF NOT EXISTS trg_expenses_updated BEFORE UPDATE ON expenses FOR EACH ROW EXECUTE FUNCTION update_updated_at();nCREATE TRIGGER IF NOT EXISTS trg_payouts_updated BEFORE UPDATE ON amazon_payouts FOR EACH ROW EXECUTE FUNCTION update_updated_at();nCREATE TRIGGER IF NOT EXISTS trg_shipments_updated BEFORE UPDATE ON fba_shipments FOR EACH ROW EXECUTE FUNCTION update_updated_at();nCREATE TRIGGER IF NOT EXISTS trg_returns_updated BEFORE UPDATE ON returns FOR EACH ROW EXECUTE FUNCTION update_updated_at();nCREATE TRIGGER IF NOT EXISTS trg_reimbursements_updated BEFORE UPDATE ON reimbursements FOR EACH ROW EXECUTE FUNCTION update_updated_at();nCREATE TRIGGER IF NOT EXISTS trg_ppc_campaigns_updated BEFORE UPDATE ON ppc_campaigns FOR EACH ROW EXECUTE FUNCTION update_updated_at();nn-- 13. VISTASnCREATE OR REPLACE VIEW monthly_financial_summary ASnSELECTn  user_id,n  DATE_TRUNC('month', expense_date)::DATE AS month,n  SUM(CASE WHEN category = 'ppc' THEN amount ELSE 0 END) AS ppc_spend,n  SUM(CASE WHEN category = 'software' THEN amount ELSE 0 END) AS software_spend,n  SUM(CASE WHEN category = 'va_services' THEN amount ELSE 0 END) AS va_spend,n  SUM(CASE WHEN category = 'samples' THEN amount ELSE 0 END) AS samples_spend,n  SUM(CASE WHEN category = 'photography' THEN amount ELSE 0 END) AS photo_spend,n  SUM(CASE WHEN category = 'shipping_forwarder' THEN amount ELSE 0 END) AS forwarder_spend,n  SUM(CASE WHEN category = 'customs' THEN amount ELSE 0 END) AS customs_spend,n  SUM(CASE WHEN category = 'prep_center' THEN amount ELSE 0 END) AS prep_spend,n  SUM(CASE WHEN category = 'storage_3pl' THEN amount ELSE 0 END) AS storage_spend,n  SUM(CASE WHEN category = 'travel' THEN amount ELSE 0 END) AS travel_spend,n  SUM(CASE WHEN category = 'other' THEN amount ELSE 0 END) AS other_spend,n  SUM(amount) AS total_expensesnFROM expensesnGROUP BY user_id, DATE_TRUNC('month', expense_date);nnCREATE OR REPLACE VIEW products_real_profit ASnSELECTn  p.id,n  p.user_id,n  p.sku,n  p.name,n  p.net_profit AS unit_profit_estimated,n  COALESCE(s.total_revenue, 0) AS total_revenue,n  COALESCE(s.total_units, 0) AS total_units_sold,n  COALESCE(r.total_returns, 0) AS total_returns,n  COALESCE(r.total_refund_amount, 0) AS total_refund_amount,n  COALESCE(e.total_expenses, 0) AS total_expenses,n  COALESCE(re.total_reimbursements, 0) AS total_reimbursements,n  (COALESCE(s.total_revenue, 0) - COALESCE(r.total_refund_amount, 0) - COALESCE(e.total_expenses, 0) + COALESCE(re.total_reimbursements, 0)) AS real_net_profitnFROM products pnLEFT JOIN (n  SELECT product_id, SUM(revenue) AS total_revenue, SUM(units_sold) AS total_unitsn  FROM sales GROUP BY product_idn) s ON s.product_id = p.idnLEFT JOIN (n  SELECT product_id, SUM(quantity) AS total_returns, SUM(refund_amount) AS total_refund_amountn  FROM returns GROUP BY product_idn) r ON r.product_id = p.idnLEFT JOIN (n  SELECT product_id, SUM(amount) AS total_expenses FROM expenses WHERE product_id IS NOT NULL GROUP BY product_idn) e ON e.product_id = p.idnLEFT JOIN (n  SELECT product_id, SUM(amount) AS total_reimbursements FROM reimbursements WHERE status = 'paid' GROUP BY product_idn) re ON re.product_id = p.id;
